exercise.solution:
*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  background-color: #f5f5f5;
  font-family: sans-serif;
}

.profile-card {
  width: 360px;
  padding: 32px;
  border: 2px solid #7eb8f7;
  margin: 40px auto;
  border-radius: 12px;
  background-color: white;
}

.profile-card h2 {
  margin-top: 0;
  margin-bottom: 12px;
  color: #1a1a2e;
}

.profile-card p {
  margin: 0;
  line-height: 1.6;
  color: #555;
}
